cmd/api/main.go:
package main

import (
	"context"
	"log"
	"net"
	"os"
	"os/signal"
	"syscall"

	"google.golang.org/grpc"
	"google.golang.org/grpc/health"
	healthpb "google.golang.org/grpc/health/grpc_health_v1"
	"google.golang.org/grpc/reflection"

	pb "github.com/your-org/test-app/gen/go/test_app/v1"
	"github.com/your-org/test-app/internal/grpcserver"
)

func main() {
	addr := ":" + getenv("PORT", "8080")
	lis, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("listen: %v", err)
	}

	grpcSrv := grpc.NewServer()

	pb.RegisterPostServiceServer(grpcSrv, grpcserver.NewPostService())
	pb.RegisterUserServiceServer(grpcSrv, grpcserver.NewUserService())

	// Standard gRPC health service — probes use grpc-health-probe or
	// the grpc.health.v1.Health endpoint.
	healthSrv := health.NewServer()
	healthpb.RegisterHealthServer(grpcSrv, healthSrv)
	healthSrv.SetServingStatus("", healthpb.HealthCheckResponse_SERVING)

	// Server reflection makes tools like grpcurl / bloomrpc work without a proto file.
	reflection.Register(grpcSrv)

	log.Printf("gRPC server listening on %s", addr)

	go func() {
		if err := grpcSrv.Serve(lis); err != nil {
			log.Fatalf("serve: %v", err)
		}
	}()

	ctx, stop := signal.NotifyContext(context.Background(), syscall.SIGTERM, syscall.SIGINT)
	defer stop()
	<-ctx.Done()

	log.Println("shutdown requested; draining connections")
	healthSrv.SetServingStatus("", healthpb.HealthCheckResponse_NOT_SERVING)
	grpcSrv.GracefulStop()
}

func getenv(k, def string) string {
	if v := os.Getenv(k); v != "" {
		return v
	}
	return def
}

